    Objects.requireNonNull(arr, "El arreglo no puede ser nulo.");
    if (from < 0 || to >= arr.length || from > to) {
        throw new IllegalArgumentException("Índices fuera de rango o inválidos.");
    }
    while (from < to) {
        V temp = arr[from];
        arr[from] = arr[to];
        arr[to] = temp;
        from++;
        to--;
    }
}

