public void abbreviate(final int nameStart, final StringBuffer buf) {
    if (buf == null || nameStart < 0 || nameStart >= buf.length()) {
        return; // No operation if buffer is null or start index is invalid
    }

    // Split the string into parts starting from nameStart
    String fullName = buf.substring(nameStart);
    String[] parts = fullName.split("\\s+"); // Split by whitespace

    if (parts.length == 0) {
        return; // No name parts to abbreviate
    }

    // Abbreviate each part except the last one
    StringBuilder abbreviatedName = new StringBuilder();
    for (int i = 0; i < parts.length - 1; i++) {
        if (!parts[i].isEmpty()) {
            abbreviatedName.append(parts[i].charAt(0)).append(".");
        }
    }

    // Append the last part as is
    abbreviatedName.append(parts[parts.length - 1]);

    // Replace the original name with the abbreviated version
    buf.replace(nameStart, buf.length(), abbreviatedName.toString());
}

/**
 * Abrevia un nombre en el buffer dado, comenzando desde el índice especificado.
 * @param nameStart inicio del nombre a abreviar.
 * @param buf buffer para agregar la abreviatura.
 */
public void abbreviate(final int nameStart, final StringBuffer buf) {
    if (buf == null || nameStart < 0 || nameStart >= buf.length()) {
        // No se puede abreviar si el buffer es nulo o el índice es inválido.
        return;
    }
    // Encuentra el primer espacio después de nameStart
    int spaceIndex = buf.indexOf(" ", nameStart);
    if (spaceIndex == -1) {
        // No hay espacio para abreviar.
        return;
    }
    // Reemplaza el nombre completo con la primera letra y un punto
    buf.replace(nameStart, spaceIndex, buf.substring(nameStart, nameStart + 1) + ".");
}

public void abbreviate(final int nameStart, final StringBuffer buf) {
    if (buf == null || nameStart < 0 || nameStart >= buf.length()) {
        return; // No operation if buffer is null or nameStart is out of bounds
    }

    // Find the first space after nameStart
    int spaceIndex = buf.indexOf(" ", nameStart);
    if (spaceIndex == -1) {
        return; // No space found, nothing to abbreviate
    }

    // Get the first character after the space
    char firstCharAfterSpace = buf.charAt(spaceIndex + 1);
    if (Character.isWhitespace(firstCharAfterSpace)) {
        return; // No character after space, nothing to abbreviate
    }

    // Replace the rest of the name with the first character after the space
    buf.replace(spaceIndex + 1, buf.length(), String.valueOf(firstCharAfterSpace));
}

